export function getSquad(teamCode: string): Squad | undefined {
  return SQUADS.find(s => s.teamCode === teamCode);
}

export function getPlayer(teamCode: string, jerseyNumber: number): SquadPlayer | undefined {
  return getSquad(teamCode)?.players.find(p => p.jerseyNumber === jerseyNumber);
}
